import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, useLocation, Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { ShieldCheck, Terminal, Activity } from 'lucide-react'; // Swapped ShieldKeyhole for ShieldCheck

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login, isProcessing } = useAuth();
  
  const navigate = useNavigate();
  const location = useLocation();
  const from = location.state?.from?.pathname || '/dashboard';

  const handleLogin = async (e) => {
    e.preventDefault();
    const toastId = toast.loading("INITIALIZING_SECURE_HANDSHAKE...");
    
    try {
      await login(email, password);
      toast.success("IDENTITY_VERIFIED: ACCESS_GRANTED", { id: toastId });
      navigate(from, { replace: true });
    } catch (err) {
      toast.error(`ERROR: ${err.message.toUpperCase()}`, { id: toastId });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#0a0a0a] font-mono p-4">
      <div className="w-full max-w-md p-8 bg-[#141414] border border-white/10 rounded-2xl shadow-2xl relative overflow-hidden">
        
        {/* Animated Scan Line */}
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/50 animate-scan" />

        <div className="flex flex-col items-center mb-10">
          <div className="w-12 h-12 bg-emerald-500/10 rounded-full flex items-center justify-center mb-4 border border-emerald-500/20">
            <ShieldCheck className="text-emerald-500" size={24} />
          </div>
          <h2 className="text-white text-lg font-bold tracking-[0.3em] uppercase">Access_Gate</h2>
          <p className="text-[9px] text-white/20 mt-1 uppercase tracking-widest">Verifying Node: 8000</p>
        </div>
        
        <form onSubmit={handleLogin} className="space-y-6">
          <div>
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-3 flex items-center gap-2">
              <Terminal size={12} /> Identity_Email
            </label>
            <input 
              type="email"
              disabled={isProcessing}
              className="w-full bg-black/40 border border-white/10 p-4 rounded-lg text-white focus:border-emerald-500/50 outline-none transition-all text-sm"
              placeholder="operator@finify.ai"
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div>
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-3 flex items-center gap-2">
              <Activity size={12} /> Secure_Key
            </label>
            <input 
              type="password"
              disabled={isProcessing}
              className="w-full bg-black/40 border border-white/10 p-4 rounded-lg text-white focus:border-emerald-500/50 outline-none transition-all text-sm"
              placeholder="••••••••"
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit"
            disabled={isProcessing}
            className={`w-full font-bold py-4 rounded-lg transition-all uppercase text-[11px] tracking-widest
              ${isProcessing 
                ? 'bg-emerald-500/20 text-emerald-500 cursor-not-allowed' 
                : 'bg-emerald-500 text-black hover:bg-emerald-400'
              }`}
          >
            {isProcessing ? 'SYNCHRONIZING...' : 'Connect_to_Terminal'}
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;
